// 에러 정보를 텔레그램 메시지로 포맷
const data = $input.first().json;

const wfName = data.workflow?.name || '알 수 없음';
const wfId = data.workflow?.id || '';
const execId = data.execution?.id || '';
const lastNode = data.execution?.lastNodeExecuted || '알 수 없음';
const errorMsg = data.execution?.error?.message || '에러 메시지 없음';
const errorStack = data.execution?.error?.stack || '';

// KST 시간 (UTC+9)
const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kst = new Date(now.getTime() + kstOffset);
const timeStr = kst.toISOString().replace('T', ' ').substring(0, 19) + ' KST';

// 실행 로그 URL
const logUrl = wfId && execId
  ? `https://n8n.pressco21.com/workflow/${wfId}/executions/${execId}`
  : 'URL 없음';

// 에러 메시지 요약 (너무 길면 자름)
const shortError = errorMsg.length > 200 ? errorMsg.substring(0, 200) + '...' : errorMsg;

const message = `🚨 [n8n 자동화 오류]\n\n워크플로우: ${wfName}\n오류 노드: ${lastNode}\n오류 내용: ${shortError}\n발생 시간: ${timeStr}\n실행 로그: ${logUrl}`;

return [{ json: { message, wfName, wfId, execId, lastNode, errorMsg } }];
